Here's a pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("http://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnFailureStatus()
    {
        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("http://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net
    public async Task FetchAsync_TimesOut_WithCancellation()
    {
        // Handler that simulates a slow response
        var handler = new DelayHandler(TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(100));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // --- Test helpers ---

    private class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        public MockHandler(HttpResponseMessage response) => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }

    private class DelayHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        public DelayHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(_delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key points:**

- **Custom `HttpMessageHandler`** — avoids real HTTP calls and gives you full control over responses and timing.
- **`[Timeout(ms)]`** — MSTest's built-in attribute prevents a test from hanging indefinitely (safety net only; your logic should cancel faster).
- **Pre-cancelled token** — verifies the method checks cancellation eagerly.
- **`CancellationTokenSource` with timeout** — simulates a real deadline against a slow handler, confirming `TaskCanceledException` propagates correctly.
